const path = require('path');

const TerminalUtils = require('../lib/jibo-cai-utils').TerminalUtils;

describe('TerminalUtils', () => {

	it('Correct command', function(done) {
		this.timeout(3000);
		const command = /^win/.test(process.platform) ? 'npm.cmd' : 'npm';
		TerminalUtils.run(command, ['version']).then(res => {
			expect(res.stdout.indexOf('npm:')).to.be.greaterThan(0);
			done();
		}).catch(done);
	});

	it('Incorrect command', (done) => {
		TerminalUtils.run('prrrd').catch( res => {
			expect(res.code).to.equal('ENOENT');
			done();
		});
	});
});
